export const SAT_QUESTION_COUNT = SAT_QUESTIONS.length;

export function getSATQuestions(topicId?: number): SATQuestion[] {
  return topicId === undefined ? SAT_QUESTIONS : SAT_QUESTIONS.filter((q) => q.topicId === topicId);
}
